    logic r_clk90_o;
    logic r_clk180_o;
    logic r_clk270_o;

    logic  s_clk0_n;

    assign clk0_o = r_clk0_o;
    assign clk90_o = r_clk90_o;
    assign clk180_o = r_clk180_o;
    assign clk270_o = r_clk270_o;
    assign rst_no = rst_ni;

